package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.SecPensioenfonds;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.RszConstantType;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import org.apache.commons.lang.NotImplementedException;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

public abstract class AbstractSectoraalPensioenFonds extends AbstractBijdrageMetPercentageBase {
    private final RszConstantService rszConstantService;
    private final ConstantManager constantManager;

    protected AbstractSectoraalPensioenFonds(RszConstantService rszConstantService, ConstantManager constantManager) {
        super(rszConstantService);
        this.rszConstantService = rszConstantService;
        this.constantManager = constantManager;
    }

    public static Konstanten getSectoraalPensioenFonds(DmfapplWnkengetal dmfapplWnkengetal) {
        if (dmfapplWnkengetal == DmfapplWnkengetal.SECTORAAL_PENSIOENFONDS_BEDIENDEN) {
            return Konstanten.CST_SECTORAAL_PENSIOENFONDS_BEDIENDEN;
        } else if (dmfapplWnkengetal == DmfapplWnkengetal.SECTORAAL_PENSIOENFONDS_ARBEIDERS) {
            return Konstanten.CST_SECTORAAL_PENSIOENFONDS_ARBEIDERS;
        } else {
            throw new NotImplementedException("Sectoraal Pensioenfonds voor werknemerkengetal " + dmfapplWnkengetal.getCode() + " nog te programmeren");
        }
    }

    public SecPensioenfonds getSectoraalPensioenFonds(DmfapplWnkengetal dmfapplWnkengetal, LocalDate zoekDatum) {
        Konstanten pensioenfonds = getSectoraalPensioenFonds(dmfapplWnkengetal);
        Constant constant = constantManager.getByCodeDatum(pensioenfonds.getCode(), zoekDatum);
        return SecPensioenfonds.getByCode(constant.getInteger());
    }

    public BigDecimal getPercentageBijdrageSectoraalPensioenfonds(SleutelGegevens gegevens, LocalDate zoekDatum, DmfapplWnkengetal dmfapplWnkengetal) {
        SecPensioenfonds sectoraalPensioenfonds = getSectoraalPensioenFonds(dmfapplWnkengetal, zoekDatum);
        WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
        return getPercentageBijdrageSectoraalPensioenfonds(zoekDatum, dmfapplWnkengetal, sectoraalPensioenfonds, werkgeversCategorie);
    }

    BigDecimal getPercentageBijdrageSectoraalPensioenfonds(
            LocalDate zoekDatum, DmfapplWnkengetal dmfapplWnkengetal, SecPensioenfonds sectoraalPensioenfonds, WerkgeversCategorie werkgeversCategorie) {
        if (sectoraalPensioenfonds == SecPensioenfonds.VOLLEDIGE_BIJDRAGE) {
            return getWerkgeversPercentageMetType(werkgeversCategorie, dmfapplWnkengetal, RszConstantType.TYPE_0, zoekDatum);
        } else if (sectoraalPensioenfonds == SecPensioenfonds.SOLIDARITEITSBIJDRAGE) {
            return getWerkgeversPercentageMetType(werkgeversCategorie, dmfapplWnkengetal, RszConstantType.TYPE_2, zoekDatum);
        } else if (sectoraalPensioenfonds == SecPensioenfonds.VRIJGESTELD) {
            return BigDecimal.ZERO;
        } else if (sectoraalPensioenfonds == SecPensioenfonds.NVT) {
            return BigDecimal.ZERO;
        } else {
            throw new UnsupportedOperationException(
                    "De enum 'Sectoraal pensioenfonds' heeft een onverwachte code " + sectoraalPensioenfonds.getCode());
        }
    }

    BigDecimal getWerkgeversPercentageMetType(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal wnkengetal, RszConstantType type, LocalDate zoekDatum) {
        RszConstant rszConstant =
                rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(werkgeversCategorie, wnkengetal, type.getCode(), zoekDatum);
        return getWerkgeversPercentage(rszConstant);
    }
}
